UPDATE public.questions SET
  stimulus_text = 'A recent study found that people who spend more time outdoors tend to have lower stress levels. ______ the study, researchers concluded that exposure to natural environments can have a positive impact on mental health. Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
