  stimulus_type = NULL,
  options = '[{"id":"A","text":"According to. This choice completes the idea as a full sentence rather than a fragment.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"According to:. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"According to,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"According to;. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The correct answer is A.  The sentence is a complete thought with a subject (the study), a verb (concluded), and an object (that exposure to natural environments can have a positive impact on mental health). This sentence introduces a new piece of information, so it needs a transition, and the transition should be a comma plus a coordinating conjunction. The conjunction "according to" is the best choice because it indicates that the new information is based on the previous information.  The other choices are incorrect because they don’t follow the conventions of Standard English.  Choices B, C, and D are incorrect because they use punctuation marks that are not used in Standard English to join two independent clauses in a sentence. Choice B is incorrect because the colon is used to introduce a list, a definition, or a series of items.  Choice C is incorrect because the comma plus the comma cannot be used to join two complete sentences.  Choice D is incorrect because a semicolon is used to connect two sentences or clauses that are related in meaning, but the clauses must be independent clauses.  In this sentence, the first clause depends on the second for its meaning, so the semicolon is not the correct punctuation mark. The passage states that "A recent study found that people who spend more time outdoors tend to have lower stress levels. ______ the study, resear…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: According to. This choice completes the idea as a full sentence rather than a fragment.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":875,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_english_8","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.903Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
